diff --git a/llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp b/llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp
index 5f28ee616f0e..30c75483f1ba 100644
--- a/llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp
+++ b/llvm/lib/Transforms/Scalar/LoopUnrollPass.cpp
@@ -1,4 +1,19 @@
 //===- LoopUnroll.cpp - Loop unroller pass --------------------------------===//
+  // If the step is an instruction, it may be zero. If the step is zero, we
+  // can't compute the trip count, so we should fall through to the original
+  // loop.
+  if (isa<Instruction>(StepV)) {
+    Value *IsZero =
+        Builder.CreateICmpEQ(StepV, ConstantInt::get(StepV->getType(), 0));
+    BasicBlock *NewBB =
+        OrigBB->splitBasicBlock(Builder.getInsertPoint(), "urtc.step0_check");
+    TerminatorInst *OldTerm = OrigBB->getTerminator();
+    Builder.SetInsertPoint(OldTerm);
+    Builder.CreateCondBr(IsZero, L->getLoopPreheader(), NewBB);
+    OldTerm->eraseFromParent();
+    OrigBB = NewBB;
+    Builder.SetInsertPoint(OrigBB->getTerminator());
+  }
